export default {
	beforeMount() {
		this.$store.commit('danse/resetAllElements');
	},
	methods: {
		addJumpElement(el) {
			this.$store.commit('danse/addJumpElement', el);
		},
		addColorElement(el) {
			this.$store.commit('danse/addColorElement', el);
		},
	},
	beforeUnmount() {
		this.$store.commit('danse/resetAllElements');
	},
};
